import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, X, Tag, Palette, Edit2, Target, DollarSign } from 'lucide-react';
import '../styles/Categorias.css';

const Categorias = () => {
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('despesa');
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedCat, setSelectedCat] = useState(null);
  
  // Incluído meta_categoria no form
  const [form, setForm] = useState({ nome: '', cor: '#4361ee', meta_categoria: '' });

  useEffect(() => {
    buscarCategorias();
  }, []);

  async function buscarCategorias() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        const { data, error } = await supabase
          .from('categorias')
          .select('*')
          .or(`user_id.eq.${user.id},user_id.is.null`)
          .order('nome');

        if (error) throw error;
        setCategorias(data || []);
      }
    } catch (error) {
      console.error("Erro ao carregar categorias:", error);
    } finally {
      setLoading(false);
    }
  }

  const openModal = (cat = null) => {
    if (cat) {
      setEditMode(true);
      setSelectedCat(cat);
      setForm({ 
        nome: cat.nome, 
        cor: cat.cor, 
        meta_categoria: cat.meta_categoria || '' 
      });
    } else {
      setEditMode(false);
      setSelectedCat(null);
      setForm({ nome: '', cor: '#4361ee', meta_categoria: '' });
    }
    setShowModal(true);
  };

  async function handleSalvar(e) {
    e.preventDefault();
    try {
      const { data: { user } } = await supabase.auth.getUser();
      
      const payload = { 
        user_id: user.id, 
        nome: form.nome, 
        tipo: activeTab, 
        cor: form.cor,
        meta_categoria: form.meta_categoria ? parseFloat(form.meta_categoria) : 0
      };

      if (editMode && selectedCat?.id) {
        const { error } = await supabase
          .from('categorias')
          .update(payload)
          .eq('id', selectedCat.id);
        
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('categorias')
          .insert([payload]);
        
        if (error) throw error;
      }

      setShowModal(false);
      buscarCategorias();
    } catch (error) {
      alert("Erro ao salvar categoria: " + error.message);
    }
  }

  async function excluirCategoria() {
    if (window.confirm(`Excluir permanentemente a categoria "${form.nome}"?`)) {
      try {
        await supabase.from('categorias').delete().eq('id', selectedCat.id);
        setShowModal(false);
        buscarCategorias();
      } catch (error) {
        console.error("Erro ao excluir:", error);
      }
    }
  }

  const formatCurrency = (val) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val || 0);
  };

  const categoriasFiltradas = categorias.filter(c => c.tipo === activeTab);

  return (
    <div className="cat-page-wrapper">
      <header className="cat-header">
        <div className="cat-title-area">
          <h1>Categorias</h1>
          <p>Gerencie seus rótulos e metas de {activeTab === 'despesa' ? 'Saídas' : 'Entradas'}</p>
        </div>
        
        <div className="cat-tab-container">
          <button 
            className={activeTab === 'provento' ? 'active' : ''} 
            onClick={() => setActiveTab('provento')}
          >
            Entradas
          </button>
          <button 
            className={activeTab === 'despesa' ? 'active' : ''} 
            onClick={() => setActiveTab('despesa')}
          >
            Saídas
          </button>
        </div>
      </header>

      <div className="cat-list-container">
        {loading ? (
          <div className="cat-status">Carregando categorias...</div>
        ) : categoriasFiltradas.length > 0 ? (
          categoriasFiltradas.map(cat => (
            <div key={cat.id} className="cat-item-row" onClick={() => openModal(cat)}>
              <div className="cat-item-main">
                <div className="cat-status-dot" style={{ backgroundColor: cat.cor }}></div>
                <div className="cat-info-text">
                  <span className="cat-item-name" style={{ color: cat.cor }}>
                    {cat.nome}
                  </span>
                  {cat.tipo === 'despesa' && (
                    <span className="cat-item-meta">Meta: {formatCurrency(cat.meta_categoria)}</span>
                  )}
                </div>
              </div>
              <Edit2 size={16} className="cat-edit-icon" />
            </div>
          ))
        ) : (
          <div className="cat-empty">Nenhuma categoria encontrada.</div>
        )}
      </div>

      <button className="cat-fab" onClick={() => openModal()} title="Nova Categoria">
        <Plus size={30} />
      </button>

      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="cat-modal" onClick={e => e.stopPropagation()}>
            <div className="cat-modal-header">
              <h3>{editMode ? 'Editar Categoria' : 'Nova Categoria'}</h3>
              <button onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>

            <form onSubmit={handleSalvar} className="cat-modal-form">
              <div className="cat-input-box">
                <label><Tag size={14}/> Nome da Categoria</label>
                <input 
                  type="text" required value={form.nome} 
                  onChange={e => setForm({...form, nome: e.target.value})} 
                  placeholder="Ex: Alimentação, Salário..."
                />
              </div>

              {activeTab === 'despesa' && (
                <div className="cat-input-box">
                  <label><Target size={14}/> Meta Mensal (Opcional)</label>
                  <div className="cat-money-input-wrapper">
                    <span className="prefix">R$</span>
                    <input 
                      type="number" step="0.01"
                      value={form.meta_categoria} 
                      onChange={e => setForm({...form, meta_categoria: e.target.value})} 
                      placeholder="0,00"
                    />
                  </div>
                </div>
              )}
              
              <div className="cat-input-box">
                <label><Palette size={14}/> Cor da Categoria</label>
                <div className="cat-color-picker-container">
                   <input 
                    type="color" className="cat-color-input"
                    value={form.cor} 
                    onChange={e => setForm({...form, cor: e.target.value})} 
                  />
                  <input 
                    type="text" className="cat-hex-input"
                    value={form.cor.toUpperCase()}
                    onChange={e => setForm({...form, cor: e.target.value})}
                    maxLength={7}
                  />
                </div>
              </div>

              <div className="cat-modal-actions">
                {editMode && (
                  <button type="button" className="btn-cat-delete" onClick={excluirCategoria}>
                    Excluir
                  </button>
                )}
                <button type="submit" className="btn-cat-save">
                  {editMode ? 'Salvar Alterações' : 'Criar Categoria'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Categorias;
